$(document).ready(function(){$(".gallery-hero").slick({autoplay:!0,arrows:!1,dots:!0,fade:!0}),$(".gallery-brand").slick({autoplay:!0,slidesToShow:3,responsive:[{breakpoint:767,settings:{slidesToShow:2}},{breakpoint:575,settings:{slidesToShow:1}}]}),$("#staffModal").on("shown.bs.modal",function(a){$(".gallery-staff").resize()}),$(".gallery-staff").slick({autoplay:!1,arrows:!0,dots:!1,fade:!0}),$("a[data-slide]").click(function(a){a.preventDefault();var s=$(this).data("slide");$(".gallery-staff").slick("slickGoTo",s-1)}),$(".gallery-testimonials").slick({autoplay:!0,arrows:!0})});